  recursive = TRUE,
  showWarnings = FALSE
)

dir.create(
  output_table_root,
  recursive = TRUE,
  showWarnings = FALSE
)

dir.create(
  output_figure_root,
  recursive = TRUE,
  showWarnings = FALSE
)


# 3. Define global plotting parameters -----------------------------------------

heatmap_color_function <- circlize::colorRamp2(
  c(
    -2,
    -1,
    0,
    1,
    2
  ),
  c(
    "#2166AC",
    "#90C0DC",
